prompt --application/shared_components/plugins/region_type/chatbot_llm_rag
begin
wwv_flow_imp_shared.create_plugin(
 p_id=>wwv_flow_imp.id(143883620194474391)
,p_plugin_type=>'REGION TYPE'
,p_name=>'CHATBOT_LLM_RAG'
,p_display_name=>'LLM Chatbot'
,p_apexlang_name=>'chatbotLlmRag'
,p_javascript_file_urls=>'#PLUGIN_FILES#js/chat_script.js'
,p_css_file_urls=>'#PLUGIN_FILES#css/chat_styles.css'
,p_plsql_code=>wwv_flow_string.join(wwv_flow_t_varchar2(
'procedure render_slider (',
'    p_plugin in            apex_plugin.t_plugin,',
'    p_region in            apex_plugin.t_region,',
'    p_param  in            apex_plugin.t_region_render_param,',
'    p_result in out nocopy apex_plugin.t_region_render_result',
') is',
'    -- -----------------------------------------------------------------',
'    -- Local variables',
'    -- -----------------------------------------------------------------',
'    l_language      varchar2(10)   := p_region.attributes.get_varchar2(''language_style'');',
'    l_region_id     varchar2(100)  := p_region.id;',
'    ',
'    -- UI texts (localized per language)',
'    l_placeholder   varchar2(100);',
'    l_send_btn      varchar2(50);',
'    l_loading_text  varchar2(100);',
'    l_error_text    varchar2(200);',
'    l_conn_error    varchar2(200);',
'    l_empty_text    varchar2(200);',
'    l_no_reply_text varchar2(200);',
'    l_dir           varchar2(3);   -- ''ltr'' or ''rtl''',
'    ',
'    l_html clob;',
'begin',
'    -- -----------------------------------------------------------------',
'    -- Step 1: Set localized texts and direction',
'    -- -----------------------------------------------------------------',
'    if l_language = ''en'' then',
'        l_placeholder  := ''Type your question here...'';',
'        l_send_btn     := ''Send'';',
unistr('        l_loading_text := ''\23F3 Thinking'';'),
unistr('        l_error_text   := ''\26A0\FE0F An error occurred while processing the reply.'';'),
unistr('        l_conn_error   := ''\26A0\FE0F Connection failed: '';'),
'        l_empty_text   := ''Ask me anything, and I will answer...'';',
'        l_no_reply_text:= ''Could not get a reply from the server.'';',
'        l_dir          := ''ltr'';',
'    else   -- Arabic (default)',
unistr('        l_placeholder  := ''\0627\0643\062A\0628 \0627\0633\062A\0641\0633\0627\0631\0643 \0647\0646\0627...'';'),
unistr('        l_send_btn     := ''\0625\0631\0633\0627\0644'';'),
unistr('        l_loading_text := ''\23F3 \062C\0627\0631\064A \0627\0644\062A\0641\0643\064A\0631'';'),
unistr('        l_error_text   := ''\26A0\FE0F \062D\062F\062B \062E\0637\0623 \0623\062B\0646\0627\0621 \0645\0639\0627\0644\062C\0629 \0627\0644\0631\062F.'';'),
unistr('        l_conn_error   := ''\26A0\FE0F \0641\0634\0644 \0627\0644\0627\062A\0635\0627\0644: '';'),
unistr('        l_empty_text   := ''\0627\0643\062A\0628 \0633\0624\0627\0644\0643 \0648\0633\0623\062C\064A\0628\0643...'';'),
unistr('        l_no_reply_text:= ''\0644\0645 \0623\0633\062A\0637\0639 \0627\0644\062D\0635\0648\0644 \0639\0644\0649 \0631\062F \0645\0646 \0627\0644\062E\0627\062F\0645.'';'),
'        l_dir          := ''rtl'';',
'    end if;',
'',
'    -- -----------------------------------------------------------------',
'    -- Step 2: Build the HTML (CSS and JS are loaded automatically',
'    --         via the plugin''s File URLs settings)',
'    -- -----------------------------------------------------------------',
'    l_html := TO_CLOB(''',
'    <div id="chatContainer_'') || l_region_id || TO_CLOB(''" ',
'         class="ai-chat-container lang-'') || l_language || TO_CLOB(''" ',
'         dir="'') || l_dir || TO_CLOB(''">',
'      <div class="ai-chat-output">',
'        <div class="ai-chat-empty">',
unistr('          <span class="ai-chat-emoji">\D83D\DCAC</span>'),
'          '') || l_empty_text || TO_CLOB(''',
'        </div>',
'      </div>',
'      <div class="ai-chat-footer">',
'        <input type="text" class="ai-chat-input" placeholder="'') || l_placeholder || TO_CLOB(''">',
'        <button type="button" class="ai-chat-btn">'') || l_send_btn || TO_CLOB(''</button>',
'      </div>',
'    </div>',
'    '');',
'',
'    -- -----------------------------------------------------------------',
'    -- Step 3: Output HTML and initialisation script (with fallback)',
'    -- -----------------------------------------------------------------',
'    sys.htp.p(l_html);',
'',
'    sys.htp.p(''',
'    <script>',
'      (function() {',
'        // Wait for DOM and ensure initAIChat is defined',
'        function init() {',
'          var container = document.getElementById("chatContainer_'' || l_region_id || ''");',
'          if (!container) return;',
'',
'          if (typeof initAIChat === "function") {',
'            initAIChat(container, {',
'              lang: "'' || l_language || ''",',
'              texts: {',
'                loading: "'' || l_loading_text || ''",',
'                error: "'' || l_error_text || ''",',
'                connError: "'' || l_conn_error || ''",',
'                noReply: "'' || l_no_reply_text || ''"',
'              }',
'            });',
'          } else {',
'            // If script not loaded yet, try again after a short delay',
'            console.warn("initAIChat not available, retrying...");',
'            setTimeout(function() {',
'              if (typeof initAIChat === "function") {',
'                initAIChat(container, {',
'                  lang: "'' || l_language || ''",',
'                  texts: {',
'                    loading: "'' || l_loading_text || ''",',
'                    error: "'' || l_error_text || ''",',
'                    connError: "'' || l_conn_error || ''",',
'                    noReply: "'' || l_no_reply_text || ''"',
'                  }',
'                });',
'              } else {',
'                console.error("initAIChat function still not available. Check that chat_script.js is loaded.");',
'              }',
'            }, 500);',
'          }',
'        }',
'',
'        if (document.readyState === "loading") {',
'          document.addEventListener("DOMContentLoaded", init);',
'        } else {',
'          init();',
'        }',
'      })();',
'    </script>',
'    '');',
'',
'exception',
'    when others then',
'        -- Fallback error message if PL/SQL fails',
unistr('        sys.htp.p(''<div style="color:red;padding:20px;">\26A0\FE0F Error loading chatbot: '' '),
'                  || substr(sqlerrm, 1, 100) || ''</div>'');',
'end render_slider;'))
,p_api_version=>3
,p_render_function=>'render_slider'
,p_version_scn=>'SH256:muw8gF2FQwPsPxwtc-r8e9K0anoOpp-qWhy68VKBJ_w'
,p_help_text=>wwv_flow_string.join(wwv_flow_t_varchar2(
'This region plugin renders an interactive AI chat interface powered by a Large Language Model (LLM) with Retrieval-Augmented Generation (RAG). Users can type questions, and the plugin sends them to a backend APEX process (AI_CHAT_PROCESS) that return'
||'s a response.',
'',
'Features:',
'- Supports English and Arabic (RTL) languages (controlled by the "Language Style" attribute).',
'- Responsive design with a clean, modern UI.',
'- Messages are displayed with language-appropriate alignment and styling.',
'- Loading indicator with animated dots.',
'- Markdown-like syntax is stripped for plain text display.',
'',
'Usage:',
'1. Create a region of type "LLM Chatbot" in your page.',
'2. Set the "Language Style" attribute to "en" for English or "ar" for Arabic (default).',
'3. Ensure the APEX process "AI_CHAT_PROCESS" exists and accepts parameter x01 (the user question) and returns JSON with a "message" key.',
'',
'Dependencies:',
'- Static files: css/chat_styles.css and js/chat_script.js (must be uploaded to the plugin''s file directory).',
'- The JavaScript function initAIChat(container, options) must be available globally.',
'- APEX server process named "AI_CHAT_PROCESS" must be defined in your application.',
'',
'The plugin automatically loads its CSS and JS via the File URLs defined in the plugin settings.'))
,p_version_identifier=>'1.0'
,p_plugin_comment=>wwv_flow_string.join(wwv_flow_t_varchar2(
'LLM Chatbot plugin v1.0',
'Author: Eng. Malek M. Al-Edresi',
'Date: 2026-07-09',
'Purpose: Provide an AI-powered chat interface with RAG capabilities.',
'',
'File structure:',
unistr('- #PLUGIN_FILES#css/chat_styles.css  \2013 all styling'),
unistr('- #PLUGIN_FILES#js/chat_script.js    \2013 all client-side logic'),
'',
'The JS file exports a global function initAIChat(container, options). The PL/SQL render procedure outputs the HTML container and calls initAIChat with language and text translations.',
'',
'The backend APEX process must be named "AI_CHAT_PROCESS" and accept x01 as the user message. It should return a JSON object with a "message" field containing the bot''s reply.',
'',
unistr('Language support: English (en) and Arabic (ar) \2013 direction, alignment, and texts are set dynamically.'),
'',
'To add new languages, extend the language conditional block in the render_slider procedure and provide translations for all UI strings.'))
,p_files_version=>2461233225735
);
wwv_flow_imp_shared.create_plugin_attribute(
 p_id=>wwv_flow_imp.id(74423376745213636)
,p_plugin_id=>wwv_flow_imp.id(143883620194474391)
,p_attribute_scope=>'COMPONENT'
,p_attribute_sequence=>1
,p_display_sequence=>10
,p_static_id=>'language_style'
,p_prompt=>'Language Style'
,p_apexlang_name=>'languageStyle'
,p_attribute_type=>'SELECT LIST'
,p_is_required=>true
,p_default_value=>'en'
,p_is_translatable=>false
,p_lov_type=>'STATIC'
);
wwv_flow_imp_shared.create_plugin_attr_value(
 p_id=>wwv_flow_imp.id(74424759899215967)
,p_plugin_attribute_id=>wwv_flow_imp.id(74423376745213636)
,p_display_sequence=>10
,p_display_value=>'Arabic'
,p_return_value=>'ar'
,p_apexlang_name=>'arabic'
,p_help_text=>'Set the style to Arabic'
);
wwv_flow_imp_shared.create_plugin_attr_value(
 p_id=>wwv_flow_imp.id(74425896189223931)
,p_plugin_attribute_id=>wwv_flow_imp.id(74423376745213636)
,p_display_sequence=>20
,p_display_value=>'English'
,p_return_value=>'en'
,p_apexlang_name=>'english'
,p_help_text=>'Set the style to English.'
);
end;
/
